import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Camera, AlertTriangle, Shield, Activity, Map, Mic, Settings, X, Play, Pause, Grid, List, Filter, ChevronLeft, ChevronRight, Maximize2 } from 'lucide-react';

// ==================== TYPES ====================
interface Detection {
  id: string;
  type: 'ppe' | 'behavior' | 'geofence' | 'fall';
  severity: 'low' | 'medium' | 'high' | 'critical';
  description: string;
  bbox?: { x: number; y: number; w: number; h: number };
  timestamp: number;
  cameraId: string;
}

interface CameraDevice {
  id: string;
  name: string;
  location: string;
  active: boolean;
  stream?: MediaStream;
  riskScore: number;
  lastDetection?: number;
  fps: number;
  status: 'online' | 'offline' | 'processing';
}

interface SafetyScore {
  overall: number;
  ppe: number;
  behavior: number;
  environment: number;
}

// ==================== CONSTANTS ====================
const MAX_LOGS = 500;
const FRAME_SKIP = 5; // پردازش هر 5 فریم
const CAMERA_WIDTH = 320; // کیفیت پایین‌تر برای scalability
const CAMERA_HEIGHT = 240;
const MAX_SIMULTANEOUS_STREAMS = 9; // حداکثر 9 stream همزمان
const CAMERAS_PER_PAGE = 9; // 3x3 grid
const WORKER_POOL_SIZE = 4; // 4 worker thread

// ==================== CAMERA GRID COMPONENT ====================
function CameraGrid({ 
  cameras, 
  visibleCameras,
  onCameraSelect,
  selectedCamera 
}: { 
  cameras: CameraDevice[];
  visibleCameras: CameraDevice[];
  onCameraSelect: (id: string) => void;
  selectedCamera: string;
}) {
  return (
    <div className="grid grid-cols-3 gap-2">
      {visibleCameras.map(cam => (
        <div
          key={cam.id}
          onClick={() => onCameraSelect(cam.id)}
          className={`relative aspect-video bg-gray-900 rounded-lg overflow-hidden cursor-pointer transition border-2 ${
            selectedCamera === cam.id ? 'border-blue-500' : 'border-gray-700'
          } ${cam.riskScore > 50 ? 'animate-pulse-danger' : ''}`}
        >
          {/* Video Preview */}
          <div className="absolute inset-0 flex items-center justify-center">
            {cam.active ? (
              <div className="w-full h-full bg-black">
                <video
                  className="w-full h-full object-cover"
                  autoPlay
                  muted
                  playsInline
                />
              </div>
            ) : (
              <Camera className="w-8 h-8 text-gray-600" />
            )}
          </div>

          {/* Camera Info Overlay */}
          <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 to-transparent p-2">
            <div className="flex items-center justify-between">
              <div className="flex-1 min-w-0">
                <p className="text-xs font-medium truncate">{cam.name}</p>
                <p className="text-[10px] text-gray-400 truncate">{cam.location}</p>
              </div>
              <div className="flex items-center gap-1">
                <div className={`w-2 h-2 rounded-full ${
                  cam.status === 'online' ? 'bg-green-500' :
                  cam.status === 'processing' ? 'bg-yellow-500 animate-pulse' :
                  'bg-red-500'
                }`} />
                {cam.riskScore > 30 && (
                  <span className="text-red-400 text-xs font-bold">
                    ⚠ {cam.riskScore}
                  </span>
                )}
              </div>
            </div>
          </div>

          {/* Risk Indicator */}
          {cam.riskScore > 70 && (
            <div className="absolute top-2 right-2">
              <AlertTriangle className="w-5 h-5 text-red-500 animate-pulse" />
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ==================== PAGINATION COMPONENT ====================
function Pagination({ 
  currentPage, 
  totalPages, 
  onPageChange 
}: {
  currentPage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
}) {
  return (
    <div className="flex items-center justify-center gap-2">
      <button
        onClick={() => onPageChange(Math.max(0, currentPage - 1))}
        disabled={currentPage === 0}
        className="p-2 bg-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-600 transition"
      >
        <ChevronRight className="w-5 h-5" />
      </button>

      <span className="text-sm">
        صفحه {currentPage + 1} از {totalPages}
      </span>

      <button
        onClick={() => onPageChange(Math.min(totalPages - 1, currentPage + 1))}
        disabled={currentPage === totalPages - 1}
        className="p-2 bg-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-600 transition"
      >
        <ChevronLeft className="w-5 h-5" />
      </button>
    </div>
  );
}

// ==================== MAIN APP ====================
export default function HSEGuardianAI() {
  // State Management
  const [cameras, setCameras] = useState<CameraDevice[]>(() => 
    // شبیه‌سازی 70 دوربین
    Array.from({ length: 70 }, (_, i) => ({
      id: `cam${i + 1}`,
      name: `دوربین ${i + 1}`,
      location: `منطقه ${Math.floor(i / 10) + 1} - بخش ${(i % 10) + 1}`,
      active: false,
      riskScore: 0,
      fps: 0,
      status: 'offline' as const
    }))
  );

  const [detections, setDetections] = useState<Detection[]>([]);
  const [safetyScore, setSafetyScore] = useState<SafetyScore>({
    overall: 95,
    ppe: 98,
    behavior: 92,
    environment: 95
  });

  const [selectedCamera, setSelectedCamera] = useState<string>('cam1');
  const [currentPage, setCurrentPage] = useState(0);
  const [viewMode, setViewMode] = useState<'grid' | 'single'>('grid');
  const [filterRisk, setFilterRisk] = useState<'all' | 'high'>('all');
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [showMap, setShowMap] = useState(false);

  const videoRefs = useRef<Map<string, HTMLVideoElement>>(new Map());
  const canvasRefs = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const frameCountRef = useRef(0);
  const workerPoolRef = useRef<Worker[]>([]);
  const processingQueueRef = useRef<string[]>([]);

  // ==================== WORKER POOL ====================
  useEffect(() => {
    // ایجاد worker pool
    console.log(`🔧 Creating ${WORKER_POOL_SIZE} worker threads...`);

    // در production اینجا worker واقعی بسازید:
    // for (let i = 0; i < WORKER_POOL_SIZE; i++) {
    //   const worker = new Worker(new URL('./workers/vision.worker.ts', import.meta.url));
    //   workerPoolRef.current.push(worker);
    // }

    return () => {
      workerPoolRef.current.forEach(w => w.terminate());
      workerPoolRef.current = [];
    };
  }, []);

  // ==================== MEMORY MANAGEMENT ====================
  const addDetection = useCallback((detection: Detection) => {
    setDetections(prev => {
      const updated = [detection, ...prev];
      return updated.slice(0, MAX_LOGS);
    });
  }, []);

  // ==================== CAMERA PAGINATION ====================
  const filteredCameras = useMemo(() => {
    if (filterRisk === 'all') return cameras;
    return cameras.filter(cam => cam.riskScore > 50);
  }, [cameras, filterRisk]);

  const totalPages = Math.ceil(filteredCameras.length / CAMERAS_PER_PAGE);

  const visibleCameras = useMemo(() => {
    const start = currentPage * CAMERAS_PER_PAGE;
    return filteredCameras.slice(start, start + CAMERAS_PER_PAGE);
  }, [filteredCameras, currentPage]);

  // ==================== PRIORITY QUEUE ====================
  const updateProcessingQueue = useCallback(() => {
    // اولویت‌بندی دوربین‌ها بر اساس risk score
    const sorted = [...cameras]
      .filter(c => c.active)
      .sort((a, b) => b.riskScore - a.riskScore)
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => c.id);

    processingQueueRef.current = sorted;
  }, [cameras]);

  useEffect(() => {
    updateProcessingQueue();
  }, [cameras, updateProcessingQueue]);

  // ==================== CAMERA MANAGEMENT ====================
  const startCamera = useCallback(async (cameraId: string) => {
    try {
      // محدودیت تعداد stream های همزمان
      const activeCount = cameras.filter(c => c.active).length;
      if (activeCount >= MAX_SIMULTANEOUS_STREAMS) {
        alert(`حداکثر ${MAX_SIMULTANEOUS_STREAMS} دوربین می‌تواند همزمان فعال باشد`);
        return;
      }

      const stream = await navigator.mediaDevices.getUserMedia({
        video: { 
          width: CAMERA_WIDTH, 
          height: CAMERA_HEIGHT,
          frameRate: 15 // FPS پایین‌تر برای کاهش CPU
        }
      });

      setCameras(prev => prev.map(cam => 
        cam.id === cameraId 
          ? { ...cam, active: true, stream, status: 'online' }
          : cam
      ));

      const video = videoRefs.current.get(cameraId);
      if (video) {
        video.srcObject = stream;
        video.play();
      }
    } catch (error) {
      console.error('Camera error:', error);
      setCameras(prev => prev.map(cam =>
        cam.id === cameraId ? { ...cam, status: 'offline' } : cam
      ));
    }
  }, [cameras]);

  const stopCamera = useCallback((cameraId: string) => {
    setCameras(prev => prev.map(cam => {
      if (cam.id === cameraId && cam.stream) {
        cam.stream.getTracks().forEach(track => track.stop());
        return { ...cam, active: false, stream: undefined, status: 'offline' };
      }
      return cam;
    }));

    const video = videoRefs.current.get(cameraId);
    if (video) video.srcObject = null;
  }, []);

  // ==================== BATCH CAMERA CONTROL ====================
  const startAllCamerasInPage = useCallback(async () => {
    const promises = visibleCameras
      .filter(c => !c.active)
      .slice(0, MAX_SIMULTANEOUS_STREAMS)
      .map(c => startCamera(c.id));

    await Promise.allSettled(promises);
  }, [visibleCameras, startCamera]);

  const stopAllCameras = useCallback(() => {
    cameras.filter(c => c.active).forEach(c => stopCamera(c.id));
  }, [cameras, stopCamera]);

  // ==================== AI DETECTION (OPTIMIZED) ====================
  const processFrame = useCallback((cameraId: string) => {
    // فقط دوربین‌های در صف پردازش
    if (!processingQueueRef.current.includes(cameraId)) return;

    const video = videoRefs.current.get(cameraId);
    const canvas = canvasRefs.current.get(cameraId);
    if (!video || !canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % FRAME_SKIP !== 0) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, CAMERA_WIDTH, CAMERA_HEIGHT);

    // شبیه‌سازی تشخیص (در production از worker استفاده کنید)
    if (Math.random() > 0.995) { // کمتر برای کاهش بار
      const detection: Detection = {
        id: `${cameraId}-${Date.now()}`,
        type: ['ppe', 'behavior', 'geofence'][Math.floor(Math.random() * 3)] as any,
        severity: ['low', 'medium', 'high'][Math.floor(Math.random() * 3)] as any,
        description: 'عدم استفاده از کلاه ایمنی',
        timestamp: Date.now(),
        cameraId
      };

      addDetection(detection);

      setCameras(prev => prev.map(cam =>
        cam.id === cameraId
          ? { ...cam, riskScore: Math.min(100, cam.riskScore + 5), lastDetection: Date.now() }
          : cam
      ));
    }
  }, [addDetection]);

  // ==================== ANIMATION LOOP (OPTIMIZED) ====================
  useEffect(() => {
    let animationFrame: number;

    const loop = () => {
      // پردازش فقط دوربین‌های در priority queue
      processingQueueRef.current.forEach(cameraId => {
        processFrame(cameraId);
      });

      animationFrame = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (animationFrame) cancelAnimationFrame(animationFrame);
    };
  }, [processFrame]);

  // ==================== AUTO-DECAY RISK SCORE ====================
  useEffect(() => {
    const interval = setInterval(() => {
      setCameras(prev => prev.map(cam => ({
        ...cam,
        riskScore: Math.max(0, cam.riskScore - 1)
      })));
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  // ==================== STATISTICS ====================
  const stats = useMemo(() => {
    const activeCameras = cameras.filter(c => c.active).length;
    const highRiskCameras = cameras.filter(c => c.riskScore > 50).length;
    const criticalDetections = detections.filter(d => d.severity === 'critical').length;

    return { activeCameras, highRiskCameras, criticalDetections };
  }, [cameras, detections]);

  // ==================== RENDER ====================
  return (
    <div className="min-h-screen bg-gray-900 text-white p-4" dir="rtl">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Shield className="w-8 h-8 text-blue-500" />
          <div>
            <h1 className="text-2xl font-bold">HSE Guardian AI Enterprise</h1>
            <p className="text-xs text-gray-400">
              {cameras.length} دوربین | {stats.activeCameras} فعال | {stats.highRiskCameras} پرخطر
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="text-center">
            <div className={`text-3xl font-bold ${
              safetyScore.overall >= 90 ? 'text-green-500' :
              safetyScore.overall >= 70 ? 'text-yellow-500' : 'text-red-500'
            }`}>
              {safetyScore.overall}
            </div>
            <div className="text-xs text-gray-400">نمره ایمنی</div>
          </div>
        </div>
      </div>

      {/* Controls */}
      <div className="mb-4 flex items-center justify-between bg-gray-800 rounded-lg p-3">
        <div className="flex items-center gap-2">
          <button
            onClick={() => setViewMode(viewMode === 'grid' ? 'single' : 'grid')}
            className="p-2 bg-gray-700 hover:bg-gray-600 rounded transition"
          >
            {viewMode === 'grid' ? <Maximize2 className="w-5 h-5" /> : <Grid className="w-5 h-5" />}
          </button>

          <select
            value={filterRisk}
            onChange={(e) => setFilterRisk(e.target.value as any)}
            className="px-3 py-2 bg-gray-700 rounded text-sm"
          >
            <option value="all">همه دوربین‌ها</option>
            <option value="high">فقط پرخطر</option>
          </select>

          <button
            onClick={startAllCamerasInPage}
            className="px-4 py-2 bg-green-600 hover:bg-green-700 rounded text-sm transition"
          >
            <Play className="w-4 h-4 inline ml-1" />
            فعال‌سازی صفحه
          </button>

          <button
            onClick={stopAllCameras}
            className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded text-sm transition"
          >
            <Pause className="w-4 h-4 inline ml-1" />
            توقف همه
          </button>
        </div>

        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          onPageChange={setCurrentPage}
        />
      </div>

      {/* Main Content */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        {/* Camera Grid */}
        <div className="lg:col-span-3 space-y-4">
          <CameraGrid
            cameras={cameras}
            visibleCameras={visibleCameras}
            onCameraSelect={setSelectedCamera}
            selectedCamera={selectedCamera}
          />

          {/* Hidden Video Elements */}
          <div className="hidden">
            {visibleCameras.map(cam => (
              <React.Fragment key={cam.id}>
                <video
                  ref={el => el && videoRefs.current.set(cam.id, el)}
                  muted
                  playsInline
                />
                <canvas
                  ref={el => el && canvasRefs.current.set(cam.id, el)}
                  width={CAMERA_WIDTH}
                  height={CAMERA_HEIGHT}
                />
              </React.Fragment>
            ))}
          </div>
        </div>

        {/* Sidebar */}
        <div className="space-y-4">
          {/* Stats */}
          <div className="bg-gray-800 rounded-lg p-4">
            <h3 className="font-bold mb-3">آمار سیستم</h3>
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-gray-400">دوربین‌های فعال</span>
                <span className="font-bold text-green-500">{stats.activeCameras}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-400">دوربین‌های پرخطر</span>
                <span className="font-bold text-red-500">{stats.highRiskCameras}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-400">تخلفات بحرانی</span>
                <span className="font-bold text-orange-500">{stats.criticalDetections}</span>
              </div>
            </div>
          </div>

          {/* Recent Detections */}
          <div className="bg-gray-800 rounded-lg p-4">
            <h3 className="font-bold mb-3 flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-yellow-500" />
              آخرین تخلفات
            </h3>

            <div className="space-y-2 max-h-96 overflow-y-auto">
              {detections.length === 0 ? (
                <p className="text-center text-gray-500 text-sm py-4">
                  بدون تخلف
                </p>
              ) : (
                detections.slice(0, 20).map(det => (
                  <div
                    key={det.id}
                    className="bg-gray-700 rounded p-2 text-xs border-r-2"
                    style={{ 
                      borderColor: det.severity === 'critical' ? '#ef4444' : '#f59e0b' 
                    }}
                  >
                    <div className="font-medium">{det.description}</div>
                    <div className="text-gray-400 mt-1">
                      {cameras.find(c => c.id === det.cameraId)?.name}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

