             {/* Note: The srcObject is set via the startCamera function directly to DOM elements 
                 stored in videoRefs. This hidden video is used for the canvas draw calls. */}
            <video
              ref={el => { if (el) videoRefs.current.set(cam.id, el); }}
              muted
              playsInline
