const { app, BrowserWindow, session } = require('electron');
const path = require('path');

// Prevent multiple instances
const gotTheLock = app.requestSingleInstanceLock();

if (!gotTheLock) {
  app.quit();
} else {
  let mainWindow;

  function createWindow() {
    mainWindow = new BrowserWindow({
      width: 1280,
      height: 720,
      minWidth: 1024,
      minHeight: 768,
      backgroundColor: '#020617', // Match slate-950
      title: 'HSE Guardian AI - Enterprise Restricted',
      webPreferences: {
        // SECURITY CRITICAL SETTINGS
        nodeIntegration: false, // Prevent renderer from using Node.js
        contextIsolation: true, // Protect against prototype pollution
        sandbox: true, // Run in a sandbox
        enableRemoteModule: false, // Disable remote module (deprecated and insecure)
        preload: path.join(__dirname, 'preload.js'), // Secure bridge
        webSecurity: true,
        allowRunningInsecureContent: false,
      },
    });

    // Remove menu bar for kiosk-like feel (prevents tampering)
    mainWindow.setMenuBarVisibility(false);

    // Load the app
    // In production, this would be the build file
    // For dev, it might be localhost
    // mainWindow.loadURL('http://localhost:3000'); 
    mainWindow.loadFile(path.join(__dirname, '../index.html'));

    // SECURITY: Prevent new windows (e.g. clicking links that open browser)
    mainWindow.webContents.setWindowOpenHandler(({ url }) => {
      // Only allow specific trusted domains if absolutely necessary
      // For this app, we deny all external navigations
      return { action: 'deny' };
    });

    // SECURITY: Verify webview creation
    mainWindow.webContents.on('will-attach-webview', (event, webPreferences, params) => {
      // Strip away preload scripts if no allowed webviews are expected
      delete webPreferences.preload;
      delete webPreferences.preloadURL;

      // Disable Node.js integration
      webPreferences.nodeIntegration = false;
      event.preventDefault(); // Deny webviews by default
    });
  }

  app.whenReady().then(() => {
    // SECURITY: CSP Header Injection
    // Enforces security even if index.html is modified
    session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
      callback({
        responseHeaders: {
          ...details.responseHeaders,
          'Content-Security-Policy': [
            "default-src 'self'; script-src 'self' 'unsafe-inline' https://cdn.tailwindcss.com https://esm.sh; style-src 'self' 'unsafe-inline'; img-src 'self' data: blob:; media-src 'self' blob:; connect-src 'self' https://esm.sh;"
          ]
        }
      });
    });

    createWindow();

    app.on('activate', () => {
      if (BrowserWindow.getAllWindows().length === 0) createWindow();
    });
  });

  app.on('window-all-closed', () => {
    if (process.platform !== 'darwin') app.quit();
  });
}

